mapper.select:
/** UsptExpertClDao.selectParntsExpertClIdList */
   select expert_cl_id
	      , expert_cl_nm
	from uspt_expert_cl
	where parnts_expert_cl_id = #{expertClId}
	order by expert_cl_id

mapper.insert:
/** UsptExpertClDao.insert */
insert into uspt_expert_cl
	(
		  expert_cl_id
		, parnts_expert_cl_id
		, expert_cl_nm
		, sort_ordr_no
		, enabled
		, creator_id
		, created_dt
		, updater_id
		, updated_dt
	)
	values
	(
		  #{expertClId}
		, #{parntsExpertClId}
		, #{expertClNm}
		, #{sortOrdrNo}
		, ${enabled}
		, #{creatorId}
		, #{createdDt}
		, #{updaterId}
		, #{updatedDt}
		)

mapper.update:
/** UsptExpertClDao.updateExpertCl */
update uspt_expert_cl
set   parnts_expert_cl_id 	= #{parntsExpertClId}
	, expert_cl_nm		  	= #{expertClNm}
	, sort_ordr_no			= #{sortOrdrNo}
	, enabled				= ${enabled}
	, updater_id			= #{updaterId}
	, updated_dt			= #{updatedDt}
where expert_cl_id = #{expertClId}

mapper.delete:
/** UsptExpertClDao.deleteExpertCl */
delete from uspt_expert_cl
where expert_cl_id = #{expertClId}

/** UsptExpertClDao.deleteExpertClParnts */
delete from uspt_expert_cl
where parnts_expert_cl_id = #{expertClId}
